package com.hospital.management.model;
/** String-backed request model; end time is deliberately absent and is calculated server-side. */
public class AppointmentForm {private Long appointmentId,patientId,doctorId;private String appointmentDate,startTime,reason,notes,status;
public Long getAppointmentId(){return appointmentId;}public void setAppointmentId(Long v){appointmentId=v;}public Long getPatientId(){return patientId;}public void setPatientId(Long v){patientId=v;}public Long getDoctorId(){return doctorId;}public void setDoctorId(Long v){doctorId=v;}public String getAppointmentDate(){return appointmentDate;}public void setAppointmentDate(String v){appointmentDate=v;}public String getStartTime(){return startTime;}public void setStartTime(String v){startTime=v;}public String getReason(){return reason;}public void setReason(String v){reason=v;}public String getNotes(){return notes;}public void setNotes(String v){notes=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}}
